use std::io;

fn main() {
    let mut input = String::new();
    io::stdin().read_line(&mut input).expect("ERROR: Empty input.");
    let mut words = input.split_whitespace();
    let k:u64 = words.next().expect("k not given.").parse().unwrap();
    let p:u64 = words.next().expect("p not given.").parse().unwrap();

    let mut sum:u64 = 0;
    for i in 1..k+1 {
        sum+=zcy(i);
        //println!("zcy({}) = {}",i,zcy(i));
    }

    //println!("{} % {}",sum,p);
    println!("{}",sum % p);
}

fn rev(n:u64) -> u64 {
    let mut rev:u64 = 0;
    let mut n = n;
    while n>0 {
        rev*=10;
        rev+=n%10;
        n/=10;
    }
    return rev;
}

fn num_digits(n:u64) -> u32 {
    let mut d:u32 = 0;
    let mut n = n;
    while n>0 {
        n/=10;
        d+=1;
    }
    return d;
}

fn zcy(n:u64) -> u64{
    n*(10u64.pow(num_digits(n)))+rev(n)
}
